<template>
    <div class="team-header-section">
        <div class="hero-container">
            <div class="hero-title">
            <h1>{{ TEAMNAME }}</h1>
            </div>

            <div class="hero-subtitle">
            <h2 ref="dynamicSubtitle"></h2>
            </div>
        </div>
    </div>
</template>

<script>
import { TEAMNAME, SUBTITLES } from "@/constants/data.js";

export default {
  name: "HeaderSection",
  props: {
    title: {
      type: String,
      default: () => TEAMNAME,
      required: false,
    },
    subtitle: {
      type: Array,
      default: () => SUBTITLES,
    },
  },
  data() {
    return {
      TEAMNAME: this.title || TEAMNAME,
      SUBTITLES: this.subtitle || SUBTITLES,
      currentSubtitleIndex: 0,
    };
  },
mounted() {
  this.$nextTick(() => {
    this.rotateSubtitles();
  });
},
methods: {
  rotateSubtitles() {
    const dynamicSubtitleElement = this.$refs.dynamicSubtitle;
    if (!dynamicSubtitleElement) return;

    let i = 0;
    const speed = 30;
    const currentText = this.SUBTITLES[this.currentSubtitleIndex];

    dynamicSubtitleElement.textContent = "";
    dynamicSubtitleElement.style.opacity = 1;

    const typeWriter = () => {
      if (i < currentText.length) {
        dynamicSubtitleElement.textContent = currentText.substring(0, i + 1);
        i++;
        setTimeout(typeWriter, speed);
      } else {
        setTimeout(() => {
          dynamicSubtitleElement.style.opacity = 0;
          setTimeout(() => {
            dynamicSubtitleElement.textContent = "";
            dynamicSubtitleElement.style.opacity = 1;
            this.currentSubtitleIndex =
              (this.currentSubtitleIndex + 1) % this.SUBTITLES.length;
            this.rotateSubtitles();
          }, 500);
        }, 3000);
      }
    };

    typeWriter();
  },
}

};
</script>
