<template>
  <div class="teams-container">
    <HeaderSection
      :subtitle="subtitle"
    />
    <GridSection
    
    />
  </div>
</template>

<script>
import teams from '@/data/team.json';
import GridSection from '@/components/team/GridSection.vue';
import HeaderSection from '@/components/team/HeaderSection.vue';

export default {
  components: {
    HeaderSection,
    GridSection
  },
  data() {
    return {
      title: teams.titles[0],
      subtitle: teams.subtitles
    };
  },
  mounted() {
    // Select a random title from the teams.json array
    const randomTitleIndex = Math.floor(Math.random() * teams.titles.length);
    const randomSubtitleIndex = Math.floor(Math.random() * teams.titles.length);
    this.title = teams.titles[randomTitleIndex];
    this.subtitle = teams.subtitles[randomSubtitleIndex];
  },
};
</script>
